function formatDateBR(date) {
  const d = String(date.getDate()).padStart(2,'0');
  const m = String(date.getMonth()+1).padStart(2,'0');
  const y = date.getFullYear();
  return `${d}-${m}-${y}`;
}

async function fetchSlotsOnce(url) {
  const r = await this.helpers.request({ method:'GET', url, headers, json:true, timeout: 300000 });
  if (r && r.success === false) {
    throw new Error('API success=false: ' + JSON.stringify(r).substring(0, 200));
  }
  return r.content?.profissional_id || r.content || {};
}

async function fetchSlots(days) {
  const now = new Date();
  const data_start = formatDateBR(now);
  const future = new Date();
  future.setDate(future.getDate() + days);
  const data_end = formatDateBR(future);

  function buildUrl(doctor) {
    let url = `${baseUrl}/appoints/available-schedule?tipo=P&procedimento_id=${doctor.procedimentoId}&profissional_id=${doctor.profissionalId}&unidade_id=0&data_start=${data_start}&data_end=${data_end}`;
    if (ctx.payment === 'plano' && ctx.plan) {
      const pNorm = ctx.plan.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      const pMatch = (doctor.planos || []).find(p => (p.nome || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').includes(pNorm));
      if (pMatch) url += `&convenio_id=${pMatch.id}`;
    }
    return url;
  }

  const doctorsToFetch = ctx.doctor.sem_preferência ? (ctx.eligible_doctors || []) : [ctx.doctor];
  const promises = doctorsToFetch.map(async (doc) => {
    const url = buildUrl(doc);
    const MAX_RETRIES = 5;
    const RETRY_DELAY_MS = 3000;

    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
      try {
        console.log(`Feegow slots for ${doc.nome} attempt ${attempt}/${MAX_RETRIES}: ${url}`);
        const result = await fetchSlotsOnce.call(this, url);
        console.log(`Feegow slots for ${doc.nome} attempt ${attempt} SUCCESS`);
        return { doc, result };
      } catch(e) {
        console.error(`Feegow slots for ${doc.nome} attempt ${attempt} FAILED: ${e.message}`);
        if (attempt < MAX_RETRIES) {
          await new Promise(resolve => setTimeout(resolve, RETRY_DELAY_MS));
        }
      }
    }
    console.error(`All ${MAX_RETRIES} Feegow attempts failed for ${doc.nome}.`);
    return { doc, result: null };
  });

  const results = await Promise.all(promises);
  const mergedMap = {};
  results.forEach(({ doc, result }) => {
    if (result && typeof result === 'object') {
      Object.entries(result).forEach(([profId, profVal]) => {
        mergedMap[profId] = {
          ...profVal,
          doctorName: doc.nome,
          doctorData: doc
        };
      });
    }
  });

  return mergedMap;
}

