}

const allSlots = processMap(profMap);

function processMap(map) {
  const list = [];
  if (!map || typeof map !== 'object') return list;
  const diasSemana = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'S\u00E1b'];
  const forbiddenLocals = ["4", "12"];
  const agoraBRT = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));

  Object.entries(map).forEach(([profId, prof]) => {
    const docName = prof.doctorName || '';
    const docData = prof.doctorData || null;
    const locals = Array.isArray(prof?.local_id) ? prof.local_id : (prof?.local_id ? [prof.local_id] : []);
    locals.forEach(loc => {
      if (!loc) return;
      Object.entries(loc).forEach(([localKey, val]) => {
        if (localKey === 'age_restriction') return;
        if (forbiddenLocals.includes(String(localKey))) return;

        const target = (val && typeof val === 'object' && !Array.isArray(val)) ? val : { [localKey]: val };

        Object.entries(target).forEach(([dateStr, horasRaw]) => {
          const horasArr = Array.isArray(horasRaw) ? horasRaw : (typeof horasRaw === 'string' ? horasRaw.trim().split(/\s+/) : []);

          horasArr.forEach(h => {
            if (!h) return;
            const parts = dateStr.split('-');
            let ano, mes, dia;
            if (parts[0].length === 4) { ano=Number(parts[0]); mes=Number(parts[1]); dia=Number(parts[2]); }
            else { dia=Number(parts[0]); mes=Number(parts[1]); ano=Number(parts[2]); }

            const hP = h.split(':');
            const dtCompare = new Date(ano, mes-1, dia, Number(hP[0]||0), Number(hP[1]||0));

            if (dtCompare > agoraBRT) {
              const dtUTC = new Date(Date.UTC(ano, mes-1, dia, 12, 0, 0));
              const diaNome = diasSemana[dtUTC.getUTCDay()];
              const labelDoc = ctx.doctor.sem_preferência ? ` (${docName})` : '';
              const label = `${diaNome}, ${String(dia).padStart(2,'0')}/${String(mes).padStart(2,'0')} \u00E0s ${h.substring(0,5)}${labelDoc}`;
              list.push({ 
                label, 
                datetime: `${ano}-${String(mes).padStart(2,'0')}-${String(dia).padStart(2,'0')}T${h}`, 
                data_feegow: `${String(dia).padStart(2,'0')}-${String(mes).padStart(2,'0')}-${ano}`, 
                hora_inicio: h.substring(0,5),
                local_id: Number(localKey),
                doctor: docData
              });
            }
          });
        });
      });
    });
  });
  return list;
}

