 */

// 1. Configurações
const FEEGOW_TOKEN = 'eyJ0eXAiOiJKV1QiLCJhbGciOiJIUzI1NiJ9.eyJpc3MiOiJmZWVnb3ciLCJhdWQiOiJwdWJsaWNhcGkiLCJpYXQiOjE3NTA5NDE4NTQsImxpY2Vuc2VJRCI6Nzk3N30.sDJdqWVAAx9eK2zC33ROygjdQR520mM-YL2aAuL7Xag';
