const headers = { 'x-access-token': token };

console.log('Iniciando Scanner Feegow (v6)...');

const fetchWithRetry = async (url, retries = 3) => {
  for (let i = 0; i < retries; i++) {
    try {
      if (i > 0) await new Promise(r => setTimeout(r, 1500 * i));
      const res = await this.helpers.request({ method: 'GET', url, headers, json: true, timeout: 300000 });
      if (res && res.success === false) {
        if (i < retries - 1) continue;
        return [];
      }
      return Array.isArray(res.content) ? res.content : [];
    } catch (e) {
      if (i === retries - 1) throw e;
    }
  }
  return [];
};

// 1. Busca Profissionais e Locais em paralelo (Timeout 60s)
const [profRes, localRes] = await Promise.all([
  this.helpers.request({ method:'GET', url:`${baseUrl}/professional/list?ativo=1`, headers, json:true, timeout: 300000 }),
  this.helpers.request({ method:'GET', url:`${baseUrl}/company/list-local`, headers, json:true, timeout: 300000 })
]);

const profs = profRes.content || [];
const locals = localRes.content || [];
const defaultLocalId = locals.length > 0 ? locals[0].id : 1;

const medicosFinal = [];

for (const prof of profs) {
  try {
    const pId = prof.profissional_id;
    const drFirstName = prof.nome.toLowerCase().split(' ')[0];
    const drEspec = (prof.especialidades?.[0]?.nome_especialidade || (prof.conselho === 'CRP' ? 'Psicologia' : 'Psiquiatria')).toLowerCase();

    console.log(`>>> Sincronizando médico: ${prof.nome} (${drEspec})`);

    // 1. Busca Planos (Com Retry para estabilidade)
    await new Promise(r => setTimeout(r, 800)); 
    let planos = [];
    try {
      const rawPlanos = await fetchWithRetry(`${baseUrl}/professional/insurance?profissional_id=${pId}`);
      planos = rawPlanos.map(i => ({ id: i.convenio_id, nome: i.nome }));
    } catch (e) {
      throw new Error(`Falha ao carregar planos: ${e.message}`);
    }

    // 2. Busca Procedimentos (Com Retry)
    await new Promise(r => setTimeout(r, 800));
    let procsRaw = [];
    try {
      procsRaw = await fetchWithRetry(`${baseUrl}/procedures/list?profissional_id=${pId}`);
    } catch (e) {
      throw new Error(`Falha ao carregar procedimentos: ${e.message}`);
    }

    const procedimentosProcessados = procsRaw
      .filter(p => { 
         const n = p.nome.toLowerCase(); 
         const isForbidden = n.includes('online') || n.includes('on-line') || n.includes('tele') || n.includes('cortesia') || n.includes('receita') || n.includes('retorno');
         if (isForbidden) return false;

         if (drEspec.includes('psiquiatr')) {
           if (n.includes('psicolo') || n.includes('psicolog')) return false;
         }
         if (drEspec.includes('psicolo')) {
           if (n.includes('psiquiatr')) return false;
         }

         const otherDrs = profs.filter(o => o.profissional_id !== pId).map(o => o.nome.toLowerCase().split(' ')[0]);
         const hasOtherName = otherDrs.some(name => name.length > 2 && new RegExp('\\b' + name + '\\b', 'i').test(n));
         const hasMyName = new RegExp('\\b' + drFirstName + '\\b', 'i').test(n);

         if (hasOtherName && !hasMyName) return false;
         return true;
      })
      .map(p => {
        const rawValor = p.valor || 0;
        let tipo = p.nome.includes(':') ? p.nome.split(':').pop().trim() : p.nome.trim();
        if (tipo.toLowerCase().includes('primeira')) {
           tipo = 'Primeira Consulta';
        } else {
           tipo = 'Consulta';
        }
        return {
          tipo,
          procedimentoId: p.procedimento_id,
          valorParticular: rawValor > 1000 ? Math.round(rawValor)/100 : rawValor
        };
      });

    const procedimentosUnicos = [];
    const seenNames = new Set();
    for (const p of procedimentosProcessados) {
      if (!seenNames.has(p.tipo)) {
        seenNames.add(p.tipo);
        procedimentosUnicos.push(p);
      }
    }
    const procedimentos = procedimentosUnicos.sort((a,b) => a.tipo.localeCompare(b.tipo));

    if (procedimentos.length > 0) {
      medicosFinal.push({
        nome: prof.nome,
        especialidade: prof.especialidades?.[0]?.nome_especialidade || (prof.conselho === 'CRP' ? 'Psicologia' : 'Psiquiatria'),
        crm: `${prof.conselho} ${prof.conselho_numero || ''}`,
        profissionalId: pId,
        localId: defaultLocalId,
        procedimentoId: procedimentos[0].procedimentoId,
        valorParticular: procedimentos[0].valorParticular,
        planos: planos,
        procedimentos: procedimentos,
        idadeMin: 0,
        idadeMax: 150,
        unidadeId: locals.find(l => l.id === defaultLocalId)?.unidade_id || 1
      });
      console.log(`   OK: ${procedimentos.length} procedimentos | ${planos.length} planos.`);
    }
  } catch (e) {
    console.error(`   ERRO em ${prof.nome}:`, e.message);
    throw new Error(`Falha ao sincronizar ${prof.nome}. Abortando o Scanner inteiro para proteger o cache antigo. Detalhe: ${e.message}`);
  }
}

console.log(`Sincronização concluída: ${medicosFinal.length} médicos mapeados.`);
if (medicosFinal.length === 0) {
  throw new Error('Sincronização resultou em 0 médicos. Abortando para não sobreescrever o cache atual com dados vazios.');
}
return [{ json: { medicos: medicosFinal, total: medicosFinal.length, updated_at: new Date() } }];

