const session = $node['Webhook API Horarios'].json.query.s;
const stateNode = $json;

if (!stateNode || !stateNode.context) {
  return [{ json: { error: 'Sessão inválida ou expirada.', slots: [] } }];
}

const ctx = typeof stateNode.context === 'string' ? JSON.parse(stateNode.context) : stateNode.context;

const baseUrl = $node['Config Clínica'].json.feegowBaseUrl;
const token = $node['Config Clínica'].json.feegowToken;
const headers = { 'x-access-token': token, 'Content-Type': 'application/json' };

function formatDateBR(date) {
  const d = String(date.getDate()).padStart(2,'0');
  const m = String(date.getMonth()+1).padStart(2,'0');
  const y = date.getFullYear();
  return `${d}-${m}-${y}`;
}

async function fetchSlotsOnce(url) {
  const r = await this.helpers.request({ method:'GET', url, headers, json:true, timeout: 300000 });
  if (r && r.success === false) {
    throw new Error('API success=false');
  }
  return r.content?.profissional_id || r.content || {};
}

async function fetchSlots(days) {
  const now = new Date();
  const data_start = formatDateBR(now);
  const future = new Date();
  future.setDate(future.getDate() + days);
  const data_end = formatDateBR(future);

  function buildUrl(doctor) {
    let url = `${baseUrl}/appoints/available-schedule?tipo=P&procedimento_id=${doctor.procedimentoId}&profissional_id=${doctor.profissionalId}&unidade_id=0&data_start=${data_start}&data_end=${data_end}`;
    if (ctx.payment === 'plano' && ctx.plan) {
      const pNorm = ctx.plan.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '');
      const pMatch = (doctor.planos || []).find(p => (p.nome || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').includes(pNorm));
      if (pMatch) url += `&convenio_id=${pMatch.id}`;
    }
    return url;
  }

  const doctorsToFetch = ctx.doctor?.sem_preferência ? (ctx.eligible_doctors || []) : [ctx.doctor];
  const promises = doctorsToFetch.map(async (doc) => {
    if (!doc || !doc.profissionalId) return { doc, result: null };
    const url = buildUrl(doc);
    try {
      const result = await fetchSlotsOnce.call(this, url);
      return { doc, result };
    } catch(e) {
      return { doc, result: null };
    }
  });

  const results = await Promise.all(promises);
  const mergedMap = {};
  results.forEach(({ doc, result }) => {
    if (result && typeof result === 'object') {
      Object.entries(result).forEach(([profId, profVal]) => {
        mergedMap[profId] = {
          ...profVal,
          doctorName: doc.nome,
          doctorData: doc
        };
      });
    }
  });
  return mergedMap;
}

const profMap = await fetchSlots(30);

if (Object.keys(profMap).length === 0) {
  return [{ json: { slots: [], doctorName: ctx.doctor?.nome || '' } }];
}

function processMap(map) {
  const list = [];
  const diasSemana = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'S\u00E1b'];
  const forbiddenLocals = ["4", "12"];
  const agoraBRT = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Sao_Paulo' }));

  Object.entries(map).forEach(([profId, prof]) => {
    const docData = prof.doctorData || null;
    const locals = Array.isArray(prof?.local_id) ? prof.local_id : (prof?.local_id ? [prof.local_id] : []);
    locals.forEach(loc => {
      if (!loc) return;
      Object.entries(loc).forEach(([localKey, val]) => {
        if (localKey === 'age_restriction') return;
        if (forbiddenLocals.includes(String(localKey))) return;

        const target = (val && typeof val === 'object' && !Array.isArray(val)) ? val : { [localKey]: val };
        Object.entries(target).forEach(([dateStr, horasRaw]) => {
          const horasArr = Array.isArray(horasRaw) ? horasRaw : (typeof horasRaw === 'string' ? horasRaw.trim().split(/\s+/) : []);

          horasArr.forEach(h => {
            if (!h) return;
            const parts = dateStr.split('-');
            let ano, mes, dia;
            if (parts[0].length === 4) { ano=Number(parts[0]); mes=Number(parts[1]); dia=Number(parts[2]); }
            else { dia=Number(parts[0]); mes=Number(parts[1]); ano=Number(parts[2]); }

            const hP = h.split(':');
            const dtCompare = new Date(ano, mes-1, dia, Number(hP[0]||0), Number(hP[1]||0));

            if (dtCompare > agoraBRT) {
              const dtUTC = new Date(Date.UTC(ano, mes-1, dia, 12, 0, 0));
              const diaNome = diasSemana[dtUTC.getUTCDay()];
              list.push({ 
                label: `${diaNome}, ${String(dia).padStart(2,'0')}/${String(mes).padStart(2,'0')} \u00E0s ${h.substring(0,5)}`, 
                datetime: `${ano}-${String(mes).padStart(2,'0')}-${String(dia).padStart(2,'0')}T${h}`, 
                data_feegow: `${String(dia).padStart(2,'0')}-${String(mes).padStart(2,'0')}-${ano}`, 
                hora_inicio: h.substring(0,5),
                local_id: Number(localKey),
                doctor: docData
              });
            }
          });
        });
      });
    });
  });
  return list;
}

const allSlots = processMap(profMap);
const uniqueSlotsMap = {};
allSlots.forEach(s => {
  if (!uniqueSlotsMap[s.datetime]) uniqueSlotsMap[s.datetime] = s;
});
const uniqueSlots = Object.values(uniqueSlotsMap);
uniqueSlots.sort((a, b) => a.datetime.localeCompare(b.datetime));

return [{ json: { 
  slots: uniqueSlots, 
  doctorName: ctx.doctor?.nome || '', 
  isSemPref: !!ctx.doctor?.sem_preferência,
  patientName: ctx.patient_name || ''
} }];

const session = $node['Webhook API Confirmar'].json.body.session;
const selectedSlot = $node['Webhook API Confirmar'].json.body.slot;
const stateNode = $json;

if (!stateNode || !stateNode.context || !selectedSlot) {
  return [{ json: { success: false, error: 'Dados inválidos ou sessão expirada.' } }];
}

const ctx = typeof stateNode.context === 'string' ? JSON.parse(stateNode.context) : stateNode.context;

