ctx.selected_slot = selectedSlot;
if (selectedSlot.doctor) {
  ctx.doctor = selectedSlot.doctor;
}

// Formata a mensagem de confirmação
let dtStr = selectedSlot.label || 'Data selecionada';
dtStr = dtStr.replace(/\s*\([^)]+\)$/, ''); // Remove nome do médico do label se tiver

let preco = '';
if (ctx.payment === 'particular' && ctx.doctor && ctx.doctor.valorParticular) {
  preco = `\n*Valor:* R$ ${Number(ctx.doctor.valorParticular).toFixed(2)}`;
}

const displayCpf = ctx.patient_cpf ? ctx.patient_cpf.replace(/(\d{3})(\d{3})(\d{3})(\d{2})/, "$1.$2.$3-$4") : '';

const reply = `*Confirmar agendamento?*\n\n*Médico:* ${ctx.doctor ? ctx.doctor.nome : ''}\n*Data/hora:* ${dtStr}\n*Paciente:* ${ctx.patient_name || ''}\n*CPF:* ${displayCpf}\n*Atendimento:* ${ctx.payment === 'plano' ? 'Plano — ' + (ctx.plan || '') : 'Particular'}${preco}\n\n1️⃣ *Confirmar*\n2️⃣ *Escolher outro horário*\n3️⃣ *Cancelar*\n\n0️⃣ *Voltar ao menu*`;

return [{
